        $(document).on('click', 'ul.editorsLeft.editors li', function() {
            var $clickedLi = $(this);
            var category = $clickedLi.find('a').text();

            if (category) {
                var author = category.toUpperCase();
                if (author === 'COLOR') {
                    author = 'COLORIST';
                }

                $('div.editorsMain ul.editorsRight li').removeClass('active');
                if (author === 'EDITOR') {
                    $('div.editorsMain ul.editorsRight li[data-start="0"]').addClass('active');
                    $('div.insideHeader div.menuRight h4.authorsNames').text('Jamil Shaukat');
                } else if (author === 'COLORIST') {
                    $('div.editorsMain ul.editorsRight li[data-start="32"]').addClass('active');
                    $('div.insideHeader div.menuRight h4.authorsNames').text('Brian Charles');
                } else if (author === 'SOUND') {
                    $('div.editorsMain ul.editorsRight li[data-start="44"]').addClass('active');
                    $('div.insideHeader div.menuRight h4.authorsNames').text('Ayo Douson');
                } else if (author === 'VFX') {
                    $('div.editorsMain ul.editorsRight li[data-start="52"]').addClass('active');
                    $('div.insideHeader div.menuRight h4.authorsNames').text('Ben Gillespie');
                }

                var targetVideo = $('.video-container .video[data-author="' + author + '"]').first();
                if (targetVideo.length) {
                    $('html, body').animate({
                        scrollTop: targetVideo.offset().top - 200
                    }, 500);
                }
            }
        });

        $(document).on('click', 'ul.editorsRight.editors li', function() {
            var artistName = $(this).find('a').text().trim();
            if (artistName) {
                var targetVideo = $('.video-container .video').filter(function() {
                    return $(this).data('title').trim() === artistName;
                }).first();

                if (targetVideo.length) {
                    $('html, body').animate({
                        scrollTop: targetVideo.offset().top - 200
                    }, 500);
                }
            }
        });

